sed -i 's/"youtube" -> resolveYouTubeUriAsync(uriString)/"youtube" -> resolveYouTubeUriAsync(uriString)\n            "soundcloud" -> resolveSoundCloudUriAsync(uriString)/g' ./app/src/main/java/com/theveloper/pixeltune/data/service/player/DualPlayerEngine.kt

sed -i '/private suspend fun resolveNeteaseUriAsync(uriString: String): Uri? {/i \    private suspend fun resolveSoundCloudUriAsync(uriString: String): Uri? {\n        Timber.tag("DualPlayerEngine").d("Async resolving SoundCloud URI: $uriString")\n\n        if (!soundCloudStreamProxy.isReady()) {\n            Timber.tag("DualPlayerEngine").w("SoundCloudStreamProxy not ready, awaiting...")\n            val proxyReady = soundCloudStreamProxy.awaitReady(5_000L)\n            if (!proxyReady) {\n                Timber.tag("DualPlayerEngine").e("SoundCloudStreamProxy not ready after timeout")\n                return null\n            }\n        }\n\n        val proxyUrl = soundCloudStreamProxy.resolveSoundCloudUri(uriString)\n        if (!proxyUrl.isNullOrBlank()) {\n            return Uri.parse(proxyUrl)\n        }\n\n        Timber.tag("DualPlayerEngine").w("Failed to resolve SoundCloud URI: $uriString")\n        return null\n    }\n' ./app/src/main/java/com/theveloper/pixeltune/data/service/player/DualPlayerEngine.kt
